     * Calling a `nonReentrant` function from another `nonReentrant`
     * function is not supported. It is possible to prevent this from happening
     * by making the `nonReentrant` function external, and making it call a
     * `private` function that does the actual work.
     */
    modifier nonReentrant() {
        _nonReentrantBefore();
        _;
        _nonReentrantAfter();
    }

    function _nonReentrantBefore() private {
        // On the first call to nonReentrant, _status will be NOT_ENTERED
        if (_status == ENTERED) {
            revert ReentrancyGuardReentrantCall();
        }

        // Any calls to nonReentrant after this point will fail
        _status = ENTERED;
    }

    function _nonReentrantAfter() private {
        // By storing the original value once again, a refund is triggered (see
        // https://eips.ethereum.org/EIPS/eip-2200)
        _status = NOT_ENTERED;
    }

    /**
     * @dev Returns true if the reentrancy guard is currently set to "entered", which indicates there is a
     * `nonReentrant` function in the call stack.
     */
    function _reentrancyGuardEntered() internal view returns (bool) {
        return _status == ENTERED;
    }
}

contracts/BondingCurveMarket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import {Math} from "@openzeppelin/contracts/utils/math/Math.sol";
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

import {MemeToken} from "./MemeToken.sol";
import {LiquidityLocker} from "./LiquidityLocker.sol";
import {IWBNB} from "./interfaces/IWBNB.sol";
import {IPancakeV3PositionManager} from "./interfaces/IPancakeV3PositionManager.sol";
import {IPancakeV3Factory} from "./interfaces/IPancakeV3Factory.sol";
import {IPancakeV3Pool} from "./interfaces/IPancakeV3Pool.sol";

contract BondingCurveMarket is ReentrancyGuard {
    using SafeERC20 for IERC20;

    int24 internal constant MIN_TICK = -887272;
    int24 internal constant MAX_TICK = 887272;

    MemeToken public immutable token;
    address public immutable creator;
    address public immutable treasury;
    uint256 public immutable targetRaise;
    uint16 public immutable buyFeeBps;
    uint16 public immutable sellFeeBps;
    uint256 public immutable virtualBnbReserve;
    uint32 public immutable antiSnipingDelaySeconds;
    uint24 public immutable pancakeFee;
    address public immutable wbnb;
    IPancakeV3PositionManager public immutable positionManager;
    LiquidityLocker public immutable locker;

    bool public migrated;
    uint256 public migratedTokenId;

    event Buy(address indexed buyer, uint256 bnbIn, uint256 tokensOut, uint256 feePaid);
    event Sell(address indexed seller, uint256 tokensIn, uint256 bnbOut, uint256 feePaid);
    event Migrated(uint256 indexed tokenId, address indexed pool, uint256 tokenAmount, uint256 wbnbAmount);

    constructor(
        address token_,
        address creator_,
        address treasury_,
        uint256 targetRaise_,
        uint16 buyFeeBps_,
        uint16 sellFeeBps_,
        uint256 virtualBnbReserve_,
        uint32 antiSnipingDelaySeconds_,
        address wbnb_,
        address positionManager_,
        address locker_,
        uint24 pancakeFee_
    ) {
        require(token_ != address(0), "token=0");
        require(creator_ != address(0), "creator=0");
        require(treasury_ != address(0), "treasury=0");
        require(wbnb_ != address(0), "wbnb=0");
        require(positionManager_ != address(0), "pm=0");
        require(locker_ != address(0), "locker=0");
        token = MemeToken(token_);
        creator = creator_;
        treasury = treasury_;
        targetRaise = targetRaise_;
        buyFeeBps = buyFeeBps_;
        sellFeeBps = sellFeeBps_;
        virtualBnbReserve = virtualBnbReserve_;
        antiSnipingDelaySeconds = antiSnipingDelaySeconds_;
        wbnb = wbnb_;
        positionManager = IPancakeV3PositionManager(positionManager_);
        locker = LiquidityLocker(locker_);
        pancakeFee = pancakeFee_;
    }

    receive() external payable {}

    function tokenReserve() public view returns (uint256) {
        return IERC20(address(token)).balanceOf(address(this));
    }

    function bnbReserve() public view returns (uint256) {
        return address(this).balance + virtualBnbReserve;
    }

    function quoteBuy(uint256 bnbIn) external view returns (uint256 tokensOut, uint256 feePaid) {
        if (migrated || bnbIn == 0) return (0, 0);
        feePaid = (bnbIn * buyFeeBps) / 10_000;
        uint256 net = bnbIn - feePaid;
        uint256 rIn = (address(this).balance + virtualBnbReserve);
        uint256 rOut = tokenReserve();
        tokensOut = _getAmountOut(net, rIn, rOut);
    }

    function quoteSell(uint256 tokensIn) external view returns (uint256 bnbOut, uint256 feePaid) {
        if (migrated || tokensIn == 0) return (0, 0);
        uint256 rIn = tokenReserve();
        uint256 rOut = (address(this).balance + virtualBnbReserve);
        uint256 gross = _getAmountOut(tokensIn, rIn, rOut);
        feePaid = (gross * sellFeeBps) / 10_000;
        bnbOut = gross - feePaid;
    }

    function buy(address recipient, uint256 minTokensOut) external payable nonReentrant returns (uint256 tokensOut) {
        require(!migrated, "migrated");
        require(recipient != address(0), "recipient=0");
        require(msg.value > 0, "value=0");

        uint256 amountIn = msg.value;
        uint256 feePaid = (amountIn * buyFeeBps) / 10_000;
        uint256 net = amountIn - feePaid;

        if (feePaid > 0) _sendBNB(treasury, feePaid);

        uint256 rInBefore = (address(this).balance - net) + virtualBnbReserve;
        uint256 rOutBefore = tokenReserve();
        tokensOut = _getAmountOut(net, rInBefore, rOutBefore);
        require(tokensOut >= minTokensOut, "slippage");

        IERC20(address(token)).safeTransfer(recipient, tokensOut);
        emit Buy(recipient, amountIn, tokensOut, feePaid);

        if (!migrated && address(this).balance >= targetRaise) {
            _migrateToPancakeV3();
        }
    }

    function sell(uint256 tokensIn, uint256 minBnbOut, address recipient) external nonReentrant returns (uint256 bnbOut) {
        require(!migrated, "migrated");
        require(tokensIn > 0, "tokens=0");
        require(recipient != address(0), "recipient=0");

        uint256 rInBefore = tokenReserve();
        uint256 rOutBefore = (address(this).balance + virtualBnbReserve);

        IERC20(address(token)).safeTransferFrom(msg.sender, address(this), tokensIn);

        uint256 gross = _getAmountOut(tokensIn, rInBefore, rOutBefore);
        require(gross <= address(this).balance, "insufficient bnb");

        uint256 feePaid = (gross * sellFeeBps) / 10_000;
        bnbOut = gross - feePaid;
        require(bnbOut >= minBnbOut, "slippage");

        if (feePaid > 0) _sendBNB(treasury, feePaid);
        _sendBNB(recipient, bnbOut);
        emit Sell(msg.sender, tokensIn, bnbOut, feePaid);
    }

    function migrateIfReady() external nonReentrant {
        require(!migrated, "migrated");
        require(address(this).balance >= targetRaise, "not ready");
        _migrateToPancakeV3();
    }

    function _migrateToPancakeV3() internal {
        migrated = true;

        uint256 tokenAmount = tokenReserve();
        uint256 bnbAmount = address(this).balance;
        require(tokenAmount > 0, "no token");
        require(bnbAmount > 0, "no bnb");

        IWBNB(wbnb).deposit{value: bnbAmount}();

        IERC20(address(token)).forceApprove(address(positionManager), tokenAmount);
        IERC20(wbnb).forceApprove(address(positionManager), bnbAmount);

        (address token0, address token1, uint256 amount0, uint256 amount1) = _sortAmounts(address(token), wbnb, tokenAmount, bnbAmount);
        uint160 sqrtPriceX96 = _sqrtPriceX96(amount0, amount1);

        positionManager.createAndInitializePoolIfNecessary(token0, token1, pancakeFee, sqrtPriceX96);

        address factory = positionManager.factory();
        address pool = IPancakeV3Factory(factory).getPool(token0, token1, pancakeFee);
        require(pool != address(0), "pool=0");

        int24 spacing = IPancakeV3Pool(pool).tickSpacing();
        require(spacing > 0, "spacing=0");
        int24 tickLower = _floorTick(MIN_TICK, spacing);
        int24 tickUpper = _ceilTick(MAX_TICK, spacing);

        (uint256 tokenId, , uint256 used0, uint256 used1) = positionManager.mint(
            IPancakeV3PositionManager.MintParams({
                token0: token0,
                token1: token1,
                fee: pancakeFee,
                tickLower: tickLower,
                tickUpper: tickUpper,
                amount0Desired: amount0,
                amount1Desired: amount1,
                amount0Min: 0,
                amount1Min: 0,
                recipient: address(locker),
                deadline: block.timestamp + 300
            })
        );

        migratedTokenId = tokenId;
        locker.registerLock(tokenId, creator, uint64(block.timestamp + 365 days));

        if (amount0 > used0) IERC20(token0).forceApprove(address(positionManager), 0);
        if (amount1 > used1) IERC20(token1).forceApprove(address(positionManager), 0);

        token.setExempt(address(positionManager), true);
        token.setExempt(address(locker), true);
        token.setTradingRestriction(uint64(block.timestamp + antiSnipingDelaySeconds));

        emit Migrated(tokenId, pool, tokenAmount, bnbAmount);
    }

    function _getAmountOut(uint256 amountIn, uint256 reserveIn, uint256 reserveOut) internal pure returns (uint256) {
        require(reserveIn > 0 && reserveOut > 0, "bad reserves");
        uint256 denominator = reserveIn + amountIn;
        return Math.mulDiv(amountIn, reserveOut, denominator);
    }

    function _sendBNB(address to, uint256 amount) internal {
        (bool ok, ) = to.call{value: amount}("");
        require(ok, "bnb transfer failed");
    }

    function _sortAmounts(
        address tokenA,
        address tokenB,
        uint256 amountA,
        uint256 amountB
    ) internal pure returns (address token0, address token1, uint256 amount0, uint256 amount1) {
        if (tokenA < tokenB) {
            token0 = tokenA;
            token1 = tokenB;
            amount0 = amountA;
            amount1 = amountB;
        } else {
            token0 = tokenB;
            token1 = tokenA;
            amount0 = amountB;
            amount1 = amountA;
        }
    }

    function _sqrtPriceX96(uint256 amount0, uint256 amount1) internal pure returns (uint160) {
        uint256 ratioX192 = Math.mulDiv(amount1, uint256(1) << 192, amount0);
        uint256 sqrtRatioX96 = Math.sqrt(ratioX192);
        require(sqrtRatioX96 <= type(uint160).max, "sqrt overflow");
        return uint160(sqrtRatioX96);
    }

    function _floorTick(int24 tick, int24 spacing) internal pure returns (int24) {
        int24 compressed = tick / spacing;
        if (tick < 0 && (tick % spacing) != 0) compressed -= 1;
        return compressed * spacing;
    }

    function _ceilTick(int24 tick, int24 spacing) internal pure returns (int24) {
        int24 compressed = tick / spacing;
        if (tick > 0 && (tick % spacing) != 0) compressed += 1;
        return compressed * spacing;
    }
}

