contracts/LiquidityLocker.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {IERC721Receiver} from "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";

import {IPancakeV3PositionManager} from "./interfaces/IPancakeV3PositionManager.sol";

contract LiquidityLocker is Ownable, IERC721Receiver {
    struct LockInfo {
        address beneficiary;
        uint64 unlockTime;
        bool claimed;
    }

    IPancakeV3PositionManager public immutable positionManager;
    mapping(address => bool) public isMarket;
    mapping(uint256 => LockInfo) public locks;

    event MarketSet(address indexed market, bool allowed);
    event Locked(uint256 indexed tokenId, address indexed beneficiary, uint64 unlockTime);
    event Claimed(uint256 indexed tokenId, address indexed beneficiary);

    constructor(address positionManager_, address owner_) Ownable(owner_) {
        require(positionManager_ != address(0), "positionManager=0");
        positionManager = IPancakeV3PositionManager(positionManager_);
    }

    modifier onlyMarket() {
        require(isMarket[msg.sender], "not market");
        _;
    }

    function setMarket(address market, bool allowed) external onlyOwner {
        isMarket[market] = allowed;
        emit MarketSet(market, allowed);
    }

    function registerLock(uint256 tokenId, address beneficiary, uint64 unlockTime) external onlyMarket {
        require(beneficiary != address(0), "beneficiary=0");
        LockInfo storage li = locks[tokenId];
        require(li.beneficiary == address(0), "already locked");
        li.beneficiary = beneficiary;
        li.unlockTime = unlockTime;
        emit Locked(tokenId, beneficiary, unlockTime);
    }

    function claim(uint256 tokenId) external {
        LockInfo storage li = locks[tokenId];
        require(li.beneficiary == msg.sender, "not beneficiary");
        require(!li.claimed, "claimed");
        require(block.timestamp >= li.unlockTime, "locked");
        li.claimed = true;
        positionManager.safeTransferFrom(address(this), msg.sender, tokenId);
        emit Claimed(tokenId, msg.sender);
    }

    function onERC721Received(address, address, uint256, bytes calldata) external view returns (bytes4) {
        require(msg.sender == address(positionManager), "only positionManager");
        return IERC721Receiver.onERC721Received.selector;
    }
}

contracts/MemeToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {ERC20} from "@openzeppelin/contracts/token/ERC20/ERC20.sol";

contract MemeToken is ERC20, Ownable {
    address public immutable factory;
    address public market;

    bool public tradingRestricted;
    uint64 public tradingOpenTime;
    mapping(address => bool) public isExempt;

    event TradingRestrictionSet(uint64 openTime);
    event ExemptSet(address indexed account, bool exempt);

    modifier onlyFactoryOrMarket() {
        require(msg.sender == factory || (market != address(0) && msg.sender == market), "not auth");
        _;
    }

    constructor(
        string memory name_,
        string memory symbol_,
        uint256 totalSupply_,
        address initialHolder_,
        address factory_
    ) ERC20(name_, symbol_) Ownable(factory_) {
        require(initialHolder_ != address(0), "holder=0");
        require(factory_ != address(0), "factory=0");
        factory = factory_;
        isExempt[factory_] = true;
        isExempt[initialHolder_] = true;
        _mint(initialHolder_, totalSupply_);
    }

    function setMarketOnce(address market_) external {
        require(msg.sender == factory, "only factory");
        require(market == address(0), "market set");
        require(market_ != address(0), "market=0");
        market = market_;
        isExempt[market_] = true;
        emit ExemptSet(market_, true);
    }

    function setExempt(address account, bool exempt) external onlyFactoryOrMarket {
        isExempt[account] = exempt;
        emit ExemptSet(account, exempt);
    }

    function setTradingRestriction(uint64 openTime) external onlyFactoryOrMarket {
        tradingRestricted = true;
        tradingOpenTime = openTime;
        emit TradingRestrictionSet(openTime);
    }

    function _update(address from, address to, uint256 value) internal override {
        if (tradingRestricted && block.timestamp < tradingOpenTime) {
            if (from != address(0) && to != address(0)) {
                if (!isExempt[from] && !isExempt[to] && !isExempt[_msgSender()]) {
                    revert("trading delayed");
                }
            }
        }
        super._update(from, to, value);
    }
}

contracts/MemeTokenFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

import {MemeToken} from "./MemeToken.sol";
import {BondingCurveMarket} from "./BondingCurveMarket.sol";
import {LiquidityLocker} from "./LiquidityLocker.sol";

contract MemeTokenFactory is Ownable {
    using SafeERC20 for IERC20;

    struct TokenInfo {
        address token;
        address market;
        address creator;
        uint40 createdAt;
        string description;
        string logo;
    }

    uint256 public constant TOTAL_SUPPLY = 1_000_000_000 ether;

    uint256 public creationFee;
    uint256 public targetRaise;
    uint256 public virtualBnbReserve;
    uint16 public buyFeeBps;
    uint16 public sellFeeBps;
    uint32 public antiSnipingDelaySeconds;
    uint24 public pancakeFee;

    address public treasury;
    address public wbnb;
    address public positionManager;
    LiquidityLocker public locker;

    address[] public allTokens;
    mapping(address => TokenInfo) public tokenInfo;

    event TokenCreated(address indexed token, address indexed market, address indexed creator);
    event TreasurySet(address indexed treasury);
    event ConfigSet();

    constructor(
        address owner_,
        address treasury_,
        address wbnb_,
        address positionManager_
    ) Ownable(owner_) {
        require(treasury_ != address(0), "treasury=0");
        require(wbnb_ != address(0), "wbnb=0");
        require(positionManager_ != address(0), "pm=0");

        treasury = treasury_;
        wbnb = wbnb_;
        positionManager = positionManager_;
        locker = new LiquidityLocker(positionManager_, address(this));

        creationFee = 0.005 ether;
        targetRaise = 16.5 ether;
        virtualBnbReserve = 1 ether;
        buyFeeBps = 100;
        sellFeeBps = 100;
        antiSnipingDelaySeconds = 120;
        pancakeFee = 2500;
    }

    receive() external payable {}

    function allTokensLength() external view returns (uint256) {
        return allTokens.length;
    }

    function setTreasury(address treasury_) external onlyOwner {
        require(treasury_ != address(0), "treasury=0");
        treasury = treasury_;
        emit TreasurySet(treasury_);
    }

    function setConfig(
        uint256 creationFee_,
        uint256 targetRaise_,
        uint256 virtualBnbReserve_,
        uint16 buyFeeBps_,
        uint16 sellFeeBps_,
        uint32 antiSnipingDelaySeconds_,
        uint24 pancakeFee_
    ) external onlyOwner {
        require(buyFeeBps_ <= 500 && sellFeeBps_ <= 500, "fee too high");
        creationFee = creationFee_;
        targetRaise = targetRaise_;
        virtualBnbReserve = virtualBnbReserve_;
        buyFeeBps = buyFeeBps_;
        sellFeeBps = sellFeeBps_;
        antiSnipingDelaySeconds = antiSnipingDelaySeconds_;
        pancakeFee = pancakeFee_;
        emit ConfigSet();
    }

    function createToken(
        string calldata name,
        string calldata symbol,
        string calldata description,
        string calldata logo
    ) external payable returns (address token, address market) {
        require(msg.value == creationFee, "bad fee");
        _sendBNB(treasury, msg.value);

        MemeToken t = new MemeToken(name, symbol, TOTAL_SUPPLY, address(this), address(this));
        BondingCurveMarket m = new BondingCurveMarket(
            address(t),
            msg.sender,
            treasury,
            targetRaise,
            buyFeeBps,
            sellFeeBps,
            virtualBnbReserve,
            antiSnipingDelaySeconds,
            wbnb,
            positionManager,
            address(locker),
            pancakeFee
        );

        t.setMarketOnce(address(m));
        IERC20(address(t)).safeTransfer(address(m), TOTAL_SUPPLY);
        locker.setMarket(address(m), true);

        t.renounceOwnership();

        token = address(t);
        market = address(m);
        allTokens.push(token);
        tokenInfo[token] = TokenInfo({
            token: token,
            market: market,
            creator: msg.sender,
            createdAt: uint40(block.timestamp),
            description: description,
            logo: logo
        });

        emit TokenCreated(token, market, msg.sender);
    }

    function _sendBNB(address to, uint256 amount) internal {
        (bool ok, ) = to.call{value: amount}("");
        require(ok, "bnb transfer failed");
    }
}
